/* ── Scroll reveal ── */
function initReveal() {
  const io = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (!e.isIntersecting) return;
      const idx = Array.from(e.target.parentElement?.children || []).indexOf(e.target);
      e.target.style.transitionDelay = `${Math.min(idx * 80, 320)}ms`;
      e.target.classList.add('in');
      io.unobserve(e.target);
    });
  }, {threshold: 0.07});
  document.querySelectorAll('.reveal').forEach(el => io.observe(el));
}

/* ── Timeline river stagger ── */
function initRiver() {
  const nodes = document.querySelectorAll('.t-node');
  const io = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (!e.isIntersecting) return;
      const idx = Array.from(nodes).indexOf(e.target);
      setTimeout(() => e.target.classList.add('in'), idx * 100);
      io.unobserve(e.target);
    });
  }, {threshold: 0.1});
  nodes.forEach(n => io.observe(n));
}

/* ── Nav active ── */
function initNav() {
  const links = document.querySelectorAll('.nav-links a[href^="#"]');
  const secs  = document.querySelectorAll('section[id]');
  window.addEventListener('scroll', () => {
    let cur = '';
    secs.forEach(s => { if (window.scrollY >= s.offsetTop - 100) cur = s.id; });
    links.forEach(a => {
      const on = a.getAttribute('href') === '#' + cur;
      a.classList.toggle('active', on);
      a.setAttribute('aria-current', on ? 'page' : 'false');
    });
  }, {passive: true});
}

/* ── Boot ── */
render(CONFIG);
initBgCanvas();
initHeroFlow();
initPipelineCanvas();
initReveal();
initRiver();
initNav();
